function parseFaqs(lines = []) {
  const faqs = [];
  let current = null;

  lines.forEach((line) => {
    if (/^\d+\.\s/.test(line)) {
      if (current) faqs.push(current);
      current = { question: line, answer: [] };
      return;
    }
    if (current) current.answer.push(line);
  });

  if (current) faqs.push(current);
  return faqs.map((faq) => ({ ...faq, answer: faq.answer.join(" ") }));
}

